mapper.select:
/*GiftVocMapper.getGiftVocList*/
SELECT ROWNUM AS RNUM , GIFT_VOC_SEQ , EXTNL_ORGN_REF_YN , FN_GET_CODENM('VOC0034', VOC_STAT) AS VOC_STAT , FN_GET_CODENM('VOC0033', VOC_TYPE) AS VOC_TYPE , CONTRACT_NUM , SUB_LINK_NAME , SUBSCRIBER_NO , LST_COM_ACTV_DATE , REQ_IN_DAY , FST_RATE_NM , LST_RATE_NM , FN_GET_CODENM('MSP0003', SUB_STATUS) AS SUB_STATUS , FN_GET_CODENM('VOC0032', ANS_STAT) AS ANS_STAT , TO_CHAR(REGST_DTTM, 'YYYYMMDD') AS REGST_DTTM , REGST_ID , FN_GET_USRNM(REGST_ID) AS REGST_NM , RECOMMEND_INFO , FN_GET_CODENM('RCP0007', ON_OFF_TYPE) AS ON_OFF_TYPE , OPEN_MARKET_REFERER , FN_GET_CODENM('VOC0030', VOC_MNG_ORGN) AS VOC_MNG_ORGN , ANS_PAY_PLAN_MON , TO_CHAR(RVISN_DTTM, 'YYYYMMDD') AS RVISN_DTTM , RVISN_ID , FN_GET_USRNM(RVISN_ID) AS RVISN_NM FROM ( /* 대외민원언급여부 Y, VOC접수상태 접수인 데이터 우선 노출*/ SELECT A.GIFT_VOC_SEQ , A.EXTNL_ORGN_REF_YN , A.VOC_STAT , A.VOC_TYPE , A.CONTRACT_NUM , B.SUB_LINK_NAME , B.SUBSCRIBER_NO , B.LST_COM_ACTV_DATE , C.REQ_IN_DAY , C.FST_RATE_NM , C.LST_RATE_NM , B.SUB_STATUS , A.ANS_STAT , A.REGST_DTTM , A.REGST_ID , C.RECOMMEND_INFO , C.ON_OFF_TYPE , C.OPEN_MARKET_REFERER , A.VOC_MNG_ORGN , A.ANS_PAY_PLAN_MON , A.RVISN_DTTM , A.RVISN_ID , A.ANS_PROC_DTTM , A.PROM_NM FROM MSP_GIFT_VOC_MGMT A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C WHERE A.CONTRACT_NUM = B.CONTRACT_NUM AND B.CONTRACT_NUM = C.CONTRACT_NUM ORDER BY (CASE WHEN A.EXTNL_ORGN_REF_YN = 'Y' AND A.VOC_STAT = 'W' THEN 1 ELSE 2 END), GIFT_VOC_SEQ DESC ) AA WHERE 1=1
AND TO_CHAR(REGST_DTTM, 'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND TO_CHAR(ANS_PROC_DTTM, 'YYYYMMDD') BETWEEN #{procStrtDt} AND #{procEndDt}
AND ANS_PAY_PLAN_MON BETWEEN #{planStrtDt} AND #{planEndDt}
AND CONTRACT_NUM = #{searchName}
AND SUBSCRIBER_NO = #{searchName}
AND SUB_LINK_NAME LIKE '%' || #{searchName} || '%'
AND PROM_NM LIKE '%' || #{searchName} || '%'
AND VOC_MNG_ORGN = #{vocMngOrgn}
AND ANS_STAT = #{ansStat}
AND VOC_TYPE = #{vocType}

mapper.update:
/*GiftVocMapper.updateGiftVoc*/
UPDATE MSP_GIFT_VOC_MGMT
SET    RVISN_DTTM = SYSDATE
	   , RVISN_ID = #{rvisnId}
	   , PROM_NM = #{promNm}
	   , GIFT_TYPE = #{giftType}
	   , GIFT_AMT = #{giftAmt}
	   , VOC_STAT = #{vocStat}
	   , DIVISN = #{divisn}
	   , RMK = #{rmk}
	   , VOC_MNG_ORGN = #{vocMngOrgn}
	   , VOC_TYPE = #{vocType}
	   , VOC_REQ_DT = #{vocReqDt}
	   , RECOMM_CONTRACT_NUM = #{recommContractNum}
	   , EXTNL_ORGN_REF_YN = DECODE(#{extnlOrgnRefYn}, 'Y', 'Y', '1', 'Y', 'N')
	   , VOC_DESC = #{vocDesc}
/*마스킹 권한자만 민감정보 수정 가능*/

	   , CUST_NM = #{custNm}
	   , VOC_CTN = #{vocCtn}
	   , USER_ID = #{userId}
	   , RECOMM_ID = #{recommId}

WHERE GIFT_VOC_SEQ = #{giftVocSeq}

/*GiftVocMapper.updateGiftVocStat*/
UPDATE MSP_GIFT_VOC_MGMT
SET    VOC_STAT = #{vocStat}
WHERE GIFT_VOC_SEQ = #{giftVocSeq}

		/*GiftVocMapper.updateGiftVocAns*/
		UPDATE MSP_GIFT_VOC_MGMT
		SET    RVISN_DTTM = SYSDATE
               , RVISN_ID = #{rvisnId}
		 	   , ANS_PROC_DTTM = SYSDATE
		 	   , ANS_PROC_ID = #{ansProcId}
		 	   , ANS_RMK = #{ansRmk}
		 	   , ANS_PAY_RSN = #{ansPayRsn}
		 	   , ANS_PAY_ITEM = #{ansPayItem}
		 	   , ANS_PAY_AMT = #{ansPayAmt}
		 	   , ANS_PAY_PLAN_MON = #{ansPayPlanMon}
		 	   , ANS_STAT = #{ansStat}
		WHERE  GIFT_VOC_SEQ = #{giftVocSeq}

