/*GiftVocMapper.dupChkGiftVoc*/
SELECT COUNT(*)
FROM MSP_GIFT_VOC_MGMT
WHERE CONTRACT_NUM = #{contractNum}
AND REGST_DTTM  >  SYSDATE - 30

mapper.insert:
/*GiftVocMapper.insertGiftVoc*/
INSERT INTO MSP_GIFT_VOC_MGMT (
		GIFT_VOC_SEQ
		, CONTRACT_NUM
		, CUST_NM
		, PROM_NM
		, GIFT_TYPE
		, GIFT_AMT
		, VOC_STAT
		, VOC_CTN
		, DIVISN
		, RMK
		, VOC_MNG_ORGN
		, VOC_TYPE
		, VOC_REQ_DT
		, USER_ID
		, RECOMM_ID
		, RECOMM_CONTRACT_NUM
		, EXTNL_ORGN_REF_YN
		, VOC_DESC
		, REGST_DTTM
		, REGST_ID
) VALUES (
		MSP_GIFT_VOC_MGMT_SEQ.NEXTVAL
		, #{contractNum}
		, #{custNm}
		, #{promNm}
		, #{giftType}
		, #{giftAmt}
		, #{vocStat}
		, #{vocCtn}
		, #{divisn}
		, #{rmk}
		, #{vocMngOrgn}
		, #{vocType}
		, #{vocReqDt}
		, #{userId}
		, #{recommId}
		, #{recommContractNum}
		, DECODE(#{extnlOrgnRefYn}, 'Y', 'Y', '1', 'Y', 'N')
		, #{vocDesc}
		, SYSDATE
		, #{regstId}
)

