/*GiftVocMapper.giftPayStatList*/
SELECT A.GIFT_PAY_STAT_SEQ , A.PAY_MON , A.CONTRACT_NUM , A.CUST_NM , A.CTN , FN_GET_CODENM('MSP0003', B.SUB_STATUS) AS SUB_STATUS , FN_GET_ORGNM(B.OPEN_AGNT_CD) AS OPEN_AGNT_NM , A.TAX_RPLY_YN , A.PROM_NM , A.GIFT_TYPE , A.GIFT_AMT FROM MSP_GIFT_PAY_STAT A , MSP_JUO_SUB_INFO B WHERE A.CONTRACT_NUM = B.CONTRACT_NUM
AND A.PAY_MON BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND A.CONTRACT_NUM = #{searchName}
AND A.CTN = #{searchName}
AND A.CUST_NM LIKE '%' || #{searchName} || '%'
AND A.GIFT_TYPE LIKE '%' || #{giftType} || '%'
AND A.PROM_NM LIKE '%' || #{promNm} || '%'

mapper.insert:
/*GiftVocMapper.insertGiftPayStat*/
INSERT INTO MSP_GIFT_PAY_STAT(
		GIFT_PAY_STAT_SEQ
		, PAY_MON
		, CONTRACT_NUM
		, CUST_NM
		, CTN
		, TAX_RPLY_YN
		, PROM_NM
		, GIFT_TYPE
		, GIFT_AMT
		, REGST_DTTM
		, REGST_ID
) VALUES (
		MSP_GIFT_PAY_STAT_SEQ.NEXTVAL
		, #{payMon}
		, #{contractNum}
		, #{custNm}
		, #{ctn}
		, #{taxRplyYn}
		, #{promNm}
		, #{giftType}
		, #{giftAmt}
		, SYSDATE
		, #{regstId}
)
